import pandas as pd
import re

clinical_file = locals()['var_function-call-10862956559198798058']
mutation_file = locals()['var_function-call-8281166126981058602']

with open(clinical_file, 'r') as f:
    clinical_data = json.load(f)

with open(mutation_file, 'r') as f:
    mutation_data = json.load(f)

mutated_patients = set(item['ParticipantBarcode'] for item in mutation_data)

records = []
barcode_pattern = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')

for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    hist_type = entry.get('histological_type')

    if 'FEMALE' not in desc:
        continue

    # Check for Breast
    if 'Breast' not in desc:
        continue

    match = barcode_pattern.search(desc)
    if match:
        barcode = match.group(1)
        if hist_type and hist_type not in ['None', 'Unknown', '[Not Applicable]']:
            has_mutation = barcode in mutated_patients
            records.append({
                'histological_type': hist_type,
                'has_mutation': has_mutation
            })

if records:
    df = pd.DataFrame(records)
    counts = df['histological_type'].value_counts()
    print("__RESULT__:")
    print(json.dumps({
        "breast_counts": counts.to_dict()
    }))
else:
    print("__RESULT__:")
    print(json.dumps({"breast_counts": {}}))
